#include <stdio.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; 
        scanf("%d", &n);
        int index = -1;
        for (int i = 0; i < n; ++i) {
            int x; 
            scanf("%d", &x);
            if (index == -1 && x == 8) {
                index = i;
            }
        }
        printf("%d", index);
        if (T) printf("\n");
    }
    return 0;
}

