import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    outputs = []
    for _ in range(T):
        n = int(next(it))
        index = -1
        for i in range(n):
            x = int(next(it))
            if index == -1 and x == 8:
                index = i
        outputs.append(str(index))
    sys.stdout.write('\n'.join(outputs))

if __name__ == "__main__":
    main()

